29	const formsComponentBlock = (items: Item[]): boolean =>
30	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === items[0].type);
31	
32	const sumOfBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
34	
35	const groupByType = (items: Item[]): Item[][] => {
36	  const groups = new Map<string, Item[]>();
37	  for (const item of items) {
